// NODO: Modify_Category_Handler (v4.0 - Final, Clean)
// OBIETTIVO: Modifica una categoria e restituisce SOLO il catalogo aggiornato,
//            esattamente nel formato che il frontend si aspetta.

// 1. RECUPERO DATI DI INPUT
const items = $input.all();
const catalogObject = items[0].json.service_catalog_setup;
const request = items[0].json.user_request;
const ownerData = items[0].json.owner_data;

// 2. ESTRAZIONE PARAMETRI
const categoryIdToUpdate = request.category_id;
const newName = request.name;
const newShortName = request.short_name;
const vatNumber = request.vat || ownerData?.vat_number; // Lo estraiamo ma NON lo mettiamo nell'output per il frontend

// 3. VALIDAZIONE
if (!catalogObject || !catalogObject.categories) throw new Error("Catalogo non valido.");
if (!categoryIdToUpdate) throw new Error("ID Categoria mancante ('category_id').");
if (!newName) throw new Error("Nuovo nome categoria mancante.");
if (!vatNumber) throw new Error("VAT number mancante.");

// 4. LOGICA DI MODIFICA
const updatedCategories = catalogObject.categories.map(category => {
  if (category.callback_data === categoryIdToUpdate) {
    return {
      ...category,
      name: newName,
      short_name: newShortName || newName
    };
  }
  return category;
});

// 5. COSTRUZIONE CATALOGO AGGIORNATO
const updatedCatalog = {
  ...catalogObject,
  categories: updatedCategories
};

// 6. RESTITUZIONE
// Restituiamo un oggetto che contiene SOLO la chiave 'catalog'.
// Il resto dei dati (vat_number, ecc.) sarà disponibile nel flusso per il nodo MongoDB,
// ma non verrà inviato al frontend.
return [{
  json: {
    catalog: updatedCatalog,
    vat_number: vatNumber // Questo serve SOLO per il prossimo nodo (MongoDB Update)
    // Il nodo Respond to Webhook dovrà essere configurato per inviare solo $json.catalog
  }
}];

// NODO: Delete_Category_Handler (v1.0 - One-Shot)
// OBIETTIVO: Rimuove una categoria dall'array e restituisce l'oggetto completo
//            pronto sia per l'UPDATE su DB che per la RESPONSE al frontend.

// 1. RECUPERO DATI DI INPUT
const items = $input.all();
const catalogObject = items[0].json.service_catalog_setup;
const request = items[0].json.user_request;
const ownerData = items[0].json.owner_data;

// 2. ESTRAZIONE PARAMETRI
const categoryIdToDelete = request.category_id; // L'ID univoco (callback_data)
const vatNumber = request.vat || ownerData?.vat_number;

// 3. VALIDAZIONE
if (!catalogObject || !catalogObject.categories) {
  throw new Error("Catalogo non valido o vuoto.");
}
if (!categoryIdToDelete) {
  throw new Error("ID Categoria da eliminare mancante ('category_id').");
}
if (!vatNumber) {
    throw new Error("VAT number mancante.");
}

// 4. LOGICA DI ELIMINAZIONE (FILTER)
// Creiamo un nuovo array mantenendo solo le categorie che NON hanno quell'ID
const updatedCategories = catalogObject.categories.filter(category => {
  return category.callback_data !== categoryIdToDelete;
});

// 5. COSTRUZIONE DEL PAYLOAD AGGIORNATO
const updatedCatalog = {
  ...catalogObject,
  categories: updatedCategories
};

// 6. RESTITUZIONE DEL PAYLOAD COMPLETO
return [{
  json: {

    catalog: updatedCatalog,
    vat_number: vatNumber
  }
}];

// --- 1. CONFIGURAZIONE ---
const BOT_TOKEN = "8378810625:AAHK3Zya8qFKD4OzFBbwSTOAGolDeY7jiJQ";
const initData = $input.item.json.body._auth;

if (!initData) return { isValid: false, error: "Dato _auth mancante" };

// --- 2. LIBRERIA CRIPTOGRAFICA PURE JS (SHA-256 & HMAC) ---
const CryptoJS = (function() {
    function sha256(m) {
        var h = [0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19];
        var k = [0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da, 0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070, 0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3, 0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2];
        var b = Array.from(typeof m === 'string' ? new TextEncoder().encode(m) : m);
        var l = b.length * 8; b.push(0x80);
        while ((b.length * 8) % 512 !== 448) b.push(0);
        for (var i = 7; i >= 0; i--) b.push((l / Math.pow(2, i * 8)) & 0xff);
        for (var i = 0; i < b.length; i += 64) {
            var w = new Int32Array(64);
            for (var j = 0; j < 16; j++) w[j] = (b[i + j * 4] << 24) | (b[i + j * 4 + 1] << 16) | (b[i + j * 4 + 2] << 8) | (b[i + j * 4 + 3]);
            for (var j = 16; j < 64; j++) {
                var s0 = ((w[j - 15] >>> 7) | (w[j - 15] << 25)) ^ ((w[j - 15] >>> 18) | (w[j - 15] << 14)) ^ (w[j - 15] >>> 3);
                var s1 = ((w[j - 2] >>> 17) | (w[j - 2] << 15)) ^ ((w[j - 2] >>> 19) | (w[j - 2] << 13)) ^ (w[j - 2] >>> 10);
                w[j] = (w[j - 16] + s0 + w[j - 7] + s1) | 0;
            }
            var [a, c, d, e, f, g, i_h, j_h] = h;
            var v = [...h];
            for (var j = 0; j < 64; j++) {
                var S1 = ((v[4] >>> 6) | (v[4] << 26)) ^ ((v[4] >>> 11) | (v[4] << 21)) ^ ((v[4] >>> 25) | (v[4] << 7));
                var ch = (v[4] & v[5]) ^ (~v[4] & v[6]);
                var t1 = (v[7] + S1 + ch + k[j] + w[j]) | 0;
                var S0 = ((v[0] >>> 2) | (v[0] << 30)) ^ ((v[0] >>> 13) | (v[0] << 19)) ^ ((v[0] >>> 22) | (v[0] << 10));
                var maj = (v[0] & v[1]) ^ (v[0] & v[2]) ^ (v[1] & v[2]);
                var t2 = (S0 + maj) | 0;
                v.unshift((t1 + t2) | 0); v.splice(8); v[4] = (v[4] + t1) | 0;
            }
            for (var j = 0; j < 8; j++) h[j] = (h[j] + v[j]) | 0;
        }
        return h.reduce((acc, val) => acc.concat([(val >>> 24) & 0xff, (val >>> 16) & 0xff, (val >>> 8) & 0xff, val & 0xff]), []);
    }

    if (typeof TextEncoder === "undefined") {
        window.TextEncoder = function() {};
        TextEncoder.prototype.encode = function(s) {
            return new Uint8Array(unescape(encodeURIComponent(s)).split("").map(c => c.charCodeAt(0)));
        };
    }

    return {
        hmac: function(key, message) {
            var k = typeof key === 'string' ? Array.from(new TextEncoder().encode(key)) : key;
            var m = Array.from(new TextEncoder().encode(message));
            var b = 64;
            if (k.length > b) k = sha256(k);
            while (k.length < b) k.push(0);
            var ipad = k.map(x => x ^ 0x36);
            var opad = k.map(x => x ^ 0x5c);
            var inner = sha256(ipad.concat(m));
            return sha256(opad.concat(inner));
        }
    };
})();

// --- 3. LOGICA PARSING ---
const data = {};
initData.split('&').forEach(pair => {
    const [k, v] = pair.split('=');
    data[k] = decodeURIComponent(v);
});

const hashReceived = data.hash;
const checkString = Object.keys(data)
    .filter(k => k !== 'hash')
    .sort()
    .map(k => k + '=' + data[k])
    .join('\n');

// --- 4. CALCOLO HASH TELEGRAM ---
const secretKey = CryptoJS.hmac("WebAppData", BOT_TOKEN);
const computedHashBytes = CryptoJS.hmac(secretKey, checkString);
const computedHash = computedHashBytes.map(b => b.toString(16).padStart(2, '0')).join('');

// --- 5. CONTROLLO SCADENZA (MAX 1 ORA) ---
const now = Math.floor(Date.now() / 1000);
const authDate = parseInt(data.auth_date);
const isExpired = (now - authDate) > 3600; // Scade dopo 3600 secondi (1 ora)

// --- 6. RISULTATO FINALE ---
const isHashValid = (computedHash === hashReceived);

return {
    isValid: isHashValid && !isExpired,
    isExpired: isExpired,
    isHashValid: isHashValid,
    user: data.user ? JSON.parse(data.user) : null,
    auth_date_human: new Date(authDate * 1000).toLocaleString('it-IT'),
    debug: {
        time_diff_seconds: now - authDate,
        computed: computedHash,
        received: hashReceived
    }
};

const item = $input.first().json;
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&'; // La tua chiave segreta

// 1. Recupero del token
const rawAsh =
  item.ash ||
  item.query?.ash ||
  item.body?.ash ||
  item.body?.web_app_data?.data ||
  item.body?.message?.web_app_data?.data;

if (!rawAsh || typeof rawAsh !== "string") {
  throw new Error("ASH non trovato nell'input.");
}

// 2. Separazione Payload e Firma
const [encodedPayload, signatureReceived] = rawAsh.split(".");

if (!encodedPayload || !signatureReceived) {
  throw new Error("Formato ASH non valido.");
}

// 3. Decodifica e verifica integrità
let decodedPayload;
try {
    decodedPayload = Buffer.from(encodedPayload, "base64").toString("utf8");
} catch (e) {
    throw new Error("Errore decodifica Base64.");
}

// --- LOGICA DI VERIFICA FIRMA ---
function verifySignature(payload, secret, receivedSig) {
    let hash = 0;
    const combined = payload + secret;
    for (let i = 0; i < combined.length; i++) {
        hash = ((hash << 5) - hash) + combined.charCodeAt(i);
        hash = hash & hash; 
    }
    const expectedSig = Math.abs(hash).toString(16);
    return expectedSig === receivedSig;
}

if (!verifySignature(decodedPayload, SECRET_KEY, signatureReceived)) {
    // Se la firma non corrisponde, blocchiamo tutto qui!
    throw new Error("SICUREZZA: Firma ASH non valida o manomessa. Accesso negato.");
}
// --------------------------------

// 4. Estrazione ID (Solo se la firma è valida)
const parts = decodedPayload.split("|");

return [{
    json: {
        ...item,
        ids: {
            owner_id: parts[0],
            timestamp: parts[1],
            webhook: parts[2]
        }
    }
}];

// Recupero i dati in ingresso
const input = items[0].json;
const productId = input.user_request.product_id;
const vatNumber = input.owner_data.vat_number;
const categories = input.service_catalog_setup.categories;

let subcategoryFound = null;

// Itero nelle categorie per trovare la subcategory corrispondente
for (const category of categories) {
    const sub = category.subcategories.find(s => s.callback_data === productId);
    if (sub) {
        subcategoryFound = sub;
        break; // Trovata, esco dal ciclo
    }
}

// Restituisco l'oggetto cercato + il vat_number
return {
    targhet_item: subcategoryFound,
    vat_number: vatNumber
};

// Recupero i dati in ingresso
const input = items[0].json;
const productId = input.user_request.product_id;
const categories = input.service_catalog_setup.categories;

// Mappo le categorie per creare il nuovo catalogo filtrato
const updatedCategories = categories.map(category => {
    return {
        ...category,
        // Filtro le subcategories escludendo quella che corrisponde al productId
        subcategories: category.subcategories.filter(sub => sub.callback_data !== productId)
    };
});

// Restituisco l'oggetto con la stessa struttura originale "service_catalog_setup"
// ma con le categorie aggiornate (senza l'item rimosso)
return {
    service_catalog_setup: {
        categories: updatedCategories
    }
};

// Ciclo su tutti gli elementi in ingresso nel nodo n8n
for (const item of $input.all()) {
  const data = item.json;

  // Verifica della presenza dei dati necessari e dell'azione corretta
  if (data.service_catalog_setup && data.user_request) {
    const userReq = data.user_request;

    if (userReq.action === 'update_product') {
      const targetProductId = userReq.product_id;
      const newName = userReq.name;
      const newShortName = userReq.short_name;
      let isUpdated = false;

      // Scorrimento delle categorie e sottocategorie per trovare il prodotto
      if (Array.isArray(data.service_catalog_setup.categories)) {
        for (const category of data.service_catalog_setup.categories) {
          if (Array.isArray(category.subcategories)) {
            for (const subcategory of category.subcategories) {
              if (subcategory.callback_data === targetProductId) {
                // Aggiornamento dei campi del prodotto trovato
                if (newName) {
                  subcategory.name = newName;
                }
                if (newShortName) {
                  subcategory.short_name = newShortName;
                }
                isUpdated = true;
                break;
              }
            }
          }
          if (isUpdated) break;
        }
      }

      // Aggiornamento opzionale dei metadati temporali in caso di modifica riuscita
      if (isUpdated && data.service_catalog_setup.metadata) {
        data.service_catalog_setup.metadata.last_updated_at = new Date().toISOString();
        data.service_catalog_setup.metadata.updated_by = "USER_INTERFACE_UPDATE";
      }
    }
  }
}

// Ritorna gli elementi modificati al nodo successivo
return $input.all();
